    alpha = 0.4
  ) |> 
   gtExtras::gt_highlight_rows(
    rows = 2,
    columns = 2,
    fill = "#E8B5A0",
    alpha = 0.4
  ) |> 
  # Row 3 highlights
  gtExtras::gt_highlight_rows(
    rows = 3,
    columns = 4,
    fill = "#B8C5D6",
    alpha = 0.4
  ) |> 
  # Row 4 highlights
  gtExtras::gt_highlight_rows(
    rows = 4,
