    fill = "#F2D4C2",
    alpha = 0.4
  ) |> 
  gtExtras::gt_highlight_rows(
    rows = 4,
    columns = c(6, 16, 24),
    fill = "#D49080",
    alpha = 0.4
  ) |> 
  gtExtras::gt_highlight_rows(
    rows = 4,
    columns = 8,
    fill = "red",
    alpha = 0.4
  ) |> 
  gtExtras::gt_highlight_rows(
    rows = 4,
    columns = 12,  # Removed duplicate
    fill = "#C17B7B",
    alpha = 0.4
  ) |> 
  gtExtras::gt_highlight_rows(
    rows = 4,
    columns = c(18, 20, 22),
    fill = "#6B8CAE",
    alpha = 0.4
  ) |> 
  gt::tab_header(title = gt::html(fball_header)) |>
  gt::tab_source_note(
